import React, { useState } from 'react';
import Sidebar from './components/Sidebar';
import { Spinner, Toast } from './components/UI';
import Dashboard     from './pages/Dashboard';
import Miembros      from './pages/Miembros';
import Cobradores    from './pages/Cobradores';
import Cobranzas     from './pages/Cobranzas';
import Reportes      from './pages/Reportes';
import Configuracion from './pages/Configuracion';
import { useSupabase } from './hooks/useSupabase';

export default function App() {
  const [tab, setTab] = useState('dashboard');

  const {
    data, loading, error, cargarTodo,
    agregarTemplo, eliminarTemplo,
    actualizarCuotas,
    agregarMiembro, eliminarMiembro,
    agregarCobrador, eliminarCobrador,
    registrarCobranza, eliminarCobranza,
  } = useSupabase();

  const renderPage = () => {
    if (loading) return <Spinner />;
    if (error) return (
      <div style={{
        background: 'var(--danger-bg)',
        border: '1px solid var(--danger)',
        borderRadius: 12,
        padding: '24px 28px',
        color: 'var(--danger)',
      }}>
        <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 8 }}>Error de conexión con Supabase</div>
        <div style={{ fontSize: 13 }}>{error}</div>
        <div style={{ fontSize: 12, marginTop: 12, opacity: 0.7 }}>
          Verificá que las variables REACT_APP_SUPABASE_URL y REACT_APP_SUPABASE_ANON_KEY
          estén correctamente definidas en el archivo <code>.env</code>.
        </div>
        <button
          onClick={cargarTodo}
          style={{
            marginTop: 16, padding: '8px 16px',
            background: 'var(--danger)', color: 'var(--white)',
            border: 'none', borderRadius: 6, cursor: 'pointer', fontWeight: 600, fontSize: 13,
          }}
        >
          Reintentar conexión
        </button>
      </div>
    );

    switch (tab) {
      case 'dashboard':     return <Dashboard data={data} />;
      case 'miembros':      return <Miembros data={data} agregarMiembro={agregarMiembro} eliminarMiembro={eliminarMiembro} />;
      case 'cobradores':    return <Cobradores data={data} agregarCobrador={agregarCobrador} eliminarCobrador={eliminarCobrador} />;
      case 'cobranzas':     return <Cobranzas data={data} registrarCobranza={registrarCobranza} eliminarCobranza={eliminarCobranza} />;
      case 'reportes':      return <Reportes data={data} />;
      case 'configuracion': return <Configuracion data={data} actualizarCuotas={actualizarCuotas} agregarTemplo={agregarTemplo} eliminarTemplo={eliminarTemplo} />;
      default:              return <Dashboard data={data} />;
    }
  };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: 'var(--gray-50)' }}>
      <Sidebar tab={tab} setTab={setTab} />

      <main style={{ flex: 1, padding: '36px 40px', overflowY: 'auto', minWidth: 0 }}>
        {/* Barra superior */}
        <div style={{
          display: 'flex',
          justifyContent: 'flex-end',
          alignItems: 'center',
          marginBottom: 28,
          gap: 12,
        }}>
          <button
            onClick={cargarTodo}
            title="Actualizar datos"
            style={{
              background: 'var(--white)',
              border: '1px solid var(--gray-200)',
              borderRadius: 8,
              padding: '7px 14px',
              fontSize: 13,
              color: 'var(--gray-600)',
              cursor: 'pointer',
              display: 'flex',
              alignItems: 'center',
              gap: 6,
              fontWeight: 500,
            }}
          >
            ↻ Actualizar
          </button>
        </div>

        {renderPage()}
      </main>
    </div>
  );
}
